export interface ProcessingState {
  status: 'idle' | 'uploading' | 'processing' | 'success' | 'error';
  message?: string;
  progress?: number;
}

export interface IRCResult {
  content: string;
  filename: string;
}

export enum FileType {
  AUDIO = 'audio',
  VIDEO = 'video'
}

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      if (typeof reader.result === 'string') {
        // Remove the data URL prefix (e.g., "data:audio/mp3;base64,")
        const base64 = reader.result.split(',')[1];
        resolve(base64);
      } else {
        reject(new Error('Failed to convert file to base64'));
      }
    };
    reader.onerror = (error) => reject(error);
  });
};

export const downloadFile = (content: string, filename: string) => {
  const blob = new Blob([content], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
};

import { GoogleGenAI } from "@google/genai";
import { fileToBase64 } from "../utils/fileHelpers";

const API_KEY = process.env.API_KEY || '';

export const generateIRCFromAudio = async (
  file: File, 
  wordsPerLine: number = 6
): Promise<string> => {
  if (!API_KEY) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const base64Data = await fileToBase64(file);

  const modelName = 'gemini-flash-latest'; 

  const prompt = `
    Task: Transcribe the provided audio file and format it as a standard LRC file (which will be saved as .irc).

    CRITICAL RULES:
    1. Break the transcription into small segments.
    2. Each segment MUST contain approximately ${wordsPerLine} words (between ${Math.max(3, wordsPerLine - 2)} and ${wordsPerLine + 1} words).
    3. Provide accurate timestamps for each segment in [mm:ss.xx] format.
    4. Return ONLY the content of the file. Do not include markdown code blocks (like \`\`\`lrc), headers, or explanations.
    5. Ensure the timestamps flow logically and correspond to the audio.
    6. If the audio is in a language other than English (e.g., Khmer, as suggested by context), transcribe it in that language accurately.

    Output Format Example:
    [00:00.00] Word one word two word three
    [00:02.15] Word four word five word six
    [00:04.50] Word seven word eight
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: file.type,
              data: base64Data
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No transcription generated.");
    }

    // Clean up any potential markdown formatting if the model disobeys
    const cleanText = text.replace(/^```[a-z]*\n/i, '').replace(/\n```$/, '').trim();
    return cleanText;

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "Failed to process audio.");
  }
};

import React, { useState, useRef } from 'react';

interface AudioUploaderProps {
  onFileSelect: (file: File) => void;
  isLoading: boolean;
}

export const AudioUploader: React.FC<AudioUploaderProps> = ({ onFileSelect, isLoading }) => {
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      validateAndPassFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      validateAndPassFile(e.target.files[0]);
    }
  };

  const validateAndPassFile = (file: File) => {
    if (file.type.startsWith('audio/') || file.type.startsWith('video/')) {
      onFileSelect(file);
    } else {
      alert("Please upload a valid audio or video file.");
    }
  };

  const onButtonClick = () => {
    inputRef.current?.click();
  };

  return (
    <div 
      className={`relative w-full p-8 border-2 border-dashed rounded-xl transition-all duration-300 ease-in-out text-center cursor-pointer
        ${dragActive ? 'border-indigo-500 bg-indigo-50' : 'border-slate-300 hover:border-slate-400 bg-white'}
        ${isLoading ? 'opacity-50 pointer-events-none' : ''}
      `}
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
      onClick={onButtonClick}
    >
      <input
        ref={inputRef}
        type="file"
        className="hidden"
        accept="audio/*,video/*"
        onChange={handleChange}
      />

      <div className="flex flex-col items-center justify-center gap-4">
        <div className={`p-4 rounded-full ${dragActive ? 'bg-indigo-100' : 'bg-slate-100'}`}>
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8 text-indigo-600">
            <path strokeLinecap="round" strokeLinejoin="round" d="M12 18.75a6 6 0 006-6v-1.5m-6 7.5a6 6 0 01-6-6v-1.5m6 7.5v3.75m-3.75 0h7.5M12 15.75a3 3 0 01-3-3V4.5a3 3 0 116 0v8.25a3 3 0 01-3 3z" />
          </svg>
        </div>
        <div>
          <h3 className="text-lg font-semibold text-slate-800">
            {isLoading ? 'Processing...' : 'Upload Audio File'}
          </h3>
          <p className="text-sm text-slate-500 mt-1">
            Drag & drop or click to select (MP3, WAV, M4A, MP4)
          </p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { IRCResult } from '../types';
import { downloadFile } from '../utils/fileHelpers';

interface ResultViewerProps {
  result: IRCResult;
  onReset: () => void;
}

export const ResultViewer: React.FC<ResultViewerProps> = ({ result, onReset }) => {
  const [content, setContent] = useState(result.content);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    setContent(result.content);
  }, [result]);

  const handleDownload = () => {
    downloadFile(content, result.filename);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="w-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full max-h-[600px]">
      <div className="flex items-center justify-between p-4 border-b border-slate-100 bg-slate-50">
        <div className="flex items-center gap-3">
            <div className="p-2 bg-green-100 rounded-lg">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5 text-green-700">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75L11.25 15 15 9.75M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
            </div>
            <div>
                <h3 className="font-semibold text-slate-800">Conversion Complete</h3>
                <p className="text-xs text-slate-500">{result.filename}</p>
            </div>
        </div>
        <div className="flex gap-2">
            <button 
                onClick={onReset}
                className="px-3 py-1.5 text-sm font-medium text-slate-600 hover:text-slate-800 hover:bg-slate-200 rounded-lg transition-colors"
            >
                New File
            </button>
        </div>
      </div>

      <div className="flex-1 p-0 relative group">
        <textarea
          value={content}
          onChange={(e) => setContent(e.target.value)}
          className="w-full h-full p-6 font-mono text-sm leading-relaxed text-slate-700 resize-none focus:outline-none focus:ring-2 focus:ring-inset focus:ring-indigo-500/20 bg-slate-50/50"
          spellCheck={false}
        />
        <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
                onClick={handleCopy}
                className="p-2 bg-white shadow-sm border border-slate-200 rounded-lg text-slate-600 hover:text-indigo-600 hover:border-indigo-200 transition-all"
                title="Copy to clipboard"
            >
                {copied ? (
                     <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
                   </svg>
                ) : (
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M15.666 3.888A2.25 2.25 0 0013.5 2.25h-3c-1.03 0-1.9.693-2.166 1.638m7.332 0c.055.194.084.4.084.612v0a.75.75 0 01-.75.75H9a.75.75 0 01-.75-.75v0c0-.212.03-.418.084-.612m7.332 0c.646.049 1.288.11 1.927.184 1.1.128 1.907 1.077 1.907 2.185V19.5a2.25 2.25 0 01-2.25 2.25H6.75A2.25 2.25 0 014.5 19.5V6.257c0-1.108.806-2.057 1.907-2.185a48.208 48.208 0 011.927-.184" />
                    </svg>
                )}
            </button>
        </div>
      </div>

      <div className="p-4 border-t border-slate-100 bg-white flex justify-end gap-3">
        <button 
            onClick={handleDownload}
            className="flex items-center gap-2 px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white font-medium rounded-lg transition-all shadow-md hover:shadow-lg active:scale-95"
        >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5M12 12.75l-3-3m0 0l3-3m-3 3h7.5" />
            </svg>
            Download .irc
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AudioUploader } from './components/AudioUploader';
import { ResultViewer } from './components/ResultViewer';
import { ProcessingState, IRCResult } from './types';
import { generateIRCFromAudio } from './services/geminiService';

const App: React.FC = () => {
  const [processingState, setProcessingState] = useState<ProcessingState>({ status: 'idle' });
  const [result, setResult] = useState<IRCResult | null>(null);
  const [file, setFile] = useState<File | null>(null);

  const handleFileSelect = async (selectedFile: File) => {
    setFile(selectedFile);
    setProcessingState({ status: 'uploading', message: 'Analyzing audio...' });

    try {
      // Simulate a small delay for UX so status isn't too flashy
      setProcessingState({ status: 'processing', message: 'Generating .irc lyrics...' });

      const ircContent = await generateIRCFromAudio(selectedFile);

      const fileNameWithoutExt = selectedFile.name.substring(0, selectedFile.name.lastIndexOf('.')) || selectedFile.name;
      const newFileName = `${fileNameWithoutExt}.irc`;

      setResult({
        content: ircContent,
        filename: newFileName
      });
      setProcessingState({ status: 'success' });
    } catch (error: any) {
      console.error(error);
      setProcessingState({ 
        status: 'error', 
        message: error.message || 'Something went wrong. Please try again.' 
      });
    }
  };

  const reset = () => {
    setFile(null);
    setResult(null);
    setProcessingState({ status: 'idle' });
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">
                I
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">IRC Converter</h1>
          </div>
          <div className="text-sm font-medium text-slate-500">
            Powered by Gemini
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-12 w-full">

        {/* Intro */}
        <div className="mb-10 text-center max-w-2xl mx-auto">
          <h2 className="text-3xl font-extrabold text-slate-900 mb-4">
            Convert Audio to .irc Lyrics
          </h2>
          <p className="text-lg text-slate-600 leading-relaxed">
            Upload your audio or video file, and our AI will transcribe and timestamp it into an IRC/LRC format, separating lines every 5-6 words.
          </p>
        </div>

        {/* Dynamic Content Area */}
        <div className="transition-all duration-500 ease-in-out">
            {processingState.status === 'error' && (
                <div className="mb-8 p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3">
                     <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6 text-red-600 shrink-0">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z" />
                    </svg>
                    <div className="flex-1">
                        <h3 className="text-sm font-semibold text-red-800">Processing Error</h3>
                        <p className="text-sm text-red-700 mt-1">{processingState.message}</p>
                        <button 
                            onClick={reset}
                            className="mt-3 text-sm font-medium text-red-800 hover:text-red-900 underline"
                        >
                            Try Again
                        </button>
                    </div>
                </div>
            )}

            {!result && processingState.status !== 'error' && (
                <div className="max-w-xl mx-auto">
                    <AudioUploader 
                        onFileSelect={handleFileSelect} 
                        isLoading={processingState.status === 'uploading' || processingState.status === 'processing'}
                    />

                    {/* Loading State Overlay/Indicator */}
                    {(processingState.status === 'uploading' || processingState.status === 'processing') && (
                        <div className="mt-8 flex flex-col items-center">
                            <div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden">
                                <div className="h-full bg-indigo-600 animate-progress"></div>
                            </div>
                            <p className="mt-3 text-sm font-medium text-slate-600 animate-pulse">
                                {processingState.message}
                            </p>
                            <p className="text-xs text-slate-400 mt-1">This may take a minute depending on file size.</p>
                        </div>
                    )}
                </div>
            )}

            {result && (
                <div className="animate-fade-in-up">
                    <ResultViewer result={result} onReset={reset} />
                </div>
            )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-8 mt-auto">
        <div className="max-w-5xl mx-auto px-4 text-center text-slate-400 text-sm">
          &copy; {new Date().getFullYear()} Audio to IRC Converter. 
        </div>
      </footer>

      <style>{`
        @keyframes progress {
          0% { width: 0%; margin-left: 0; }
          50% { width: 50%; margin-left: 25%; }
          100% { width: 100%; margin-left: 0; }
        }
        .animate-progress {
          animation: progress 2s infinite ease-in-out;
        }
        @keyframes fadeInUp {
            from { opacity: 0; transform: translateY(20px); }
            to { opacity: 1; transform: translateY(0); }
        }
        .animate-fade-in-up {
            animation: fadeInUp 0.5s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;
